
window.mudxGeneral={copyToClipboard:async function(copyText){try{if(!document.hasFocus()){window.focus();}
await navigator.clipboard.writeText(copyText);return"success";}catch(error){console.error('Clipboard copy failed:',error);try{const textarea=document.createElement('textarea');textarea.value=copyText;textarea.style.position='fixed';textarea.style.opacity='0';document.body.appendChild(textarea);textarea.select();const successful=document.execCommand('copy');document.body.removeChild(textarea);return successful?"success":"fallback failed";}catch(fallbackError){console.error('Fallback copy failed:',fallbackError);return`Copy and Fallback failed:${fallbackError}`;}}},};